    // ── Seed helper ───────────────────────────────────────────────────────

    private async Task SeedTemplateAsync(VmTemplate template, CancellationToken ct)
    {
        var existing = await _dataStore.GetTemplateBySlugAsync(template.Slug);

        if (existing is not null && existing.Revision >= template.Revision)
        {
            _logger.LogDebug(
                "System template '{Slug}' r{Stored} ≥ seeder r{New} — skipping",
                template.Slug, existing.Revision, template.Revision);
            return;
        }

        if (existing is not null)
        {
            template.Id = existing.Id; // preserve MongoDB _id — update in-place
            _logger.LogInformation(
                "Updating system template '{Slug}': r{Old} → r{New}",
                template.Slug, existing.Revision, template.Revision);
        }
        else
        {
            _logger.LogInformation(
                "Seeding new system template '{Slug}' r{Rev}",
                template.Slug, template.Revision);
        }

        await _dataStore.SaveTemplateAsync(template);

        _logger.LogInformation(
            "✓ System template '{Slug}' seeded " +
            "(r{Rev}, {HttpsCount} HTTPS + {InlineCount} inline artifacts)",
            template.Slug,
            template.Revision,
            template.Artifacts.Count(a => !a.IsInline),
            template.Artifacts.Count(a => a.IsInline));
    }

    /// <summary>
    /// Fetch a cloud-init YAML template from DeCloud.Builds at the pinned git ref.
    /// Throws on network failure — seed will log and abort cleanly so the
    /// orchestrator starts with the previously-stored template in MongoDB.
    /// </summary>
    private async Task<string> FetchCloudInitAsync(string role, CancellationToken ct)
    {
        var url = $"{CloudInitRawBase}/{role}/cloudinit.yaml";
        _logger.LogDebug("Fetching cloudinit for '{Role}' from {Url}", role, url);
        return await _httpClient.GetStringAsync(url, ct);
    }

    // ── Artifact factory ──────────────────────────────────────────────────

    private static TemplateArtifact Artifact(
        string name,
        string description,
        ArtifactType type,
        string sha256,
        string sourceUrl,
        string? arch = null,
        long sizeBytes = 0)
    {
        // Verify the data: URI SHA256 matches at seed time (cheap — bytes are inline).
        // This catches constant mismatches caused by editing one but not the other.
        if (sourceUrl.StartsWith("data:", StringComparison.OrdinalIgnoreCase) &&
            sha256 != "COMPUTE_FROM_FILE")
        {
            var commaIndex = sourceUrl.IndexOf(',');
            if (commaIndex >= 0)
            {
                var bytes = Convert.FromBase64String(sourceUrl[(commaIndex + 1)..].Trim());
                var actual = Convert.ToHexString(SHA256.HashData(bytes)).ToLowerInvariant();
                if (!string.Equals(actual, sha256, StringComparison.OrdinalIgnoreCase))
                    throw new InvalidOperationException(
                        $"SystemVmTemplateSeeder: inline artifact '{name}' SHA256 mismatch. " +
                        $"Expected {sha256[..12]}, actual {actual[..12]}. " +
                        "Run compute-artifact-constants.sh to regenerate constants.");

                sizeBytes = bytes.Length;
            }
        }

        return new TemplateArtifact
        {
            Name = name,
            Description = description,
            Type = type,
            Architecture = arch,
            Sha256 = sha256,
            SizeBytes = sizeBytes,
            SourceUrl = sourceUrl,
            RegisteredAt = DateTime.UtcNow,
            RegisteredBy = "system",
        };
    }
}